from haystack import Pipeline, component

@component
class TaskRouter:
    @component.output_types(next_step=str)
    def run(self, task: str):
        return next_step='api_call' if 'transfer' in task else 'approval'

@component
class APICaller:
    @component.output_types(result=dict)
    def run(self, params: dict):
        # Simulate API call
        return result={'status': 'success', 'data': params}

p = Pipeline()
p.add_component('router', TaskRouter())
p.add_component('api_caller', APICaller())
p.connect('router.next_step', 'api_caller')

result = p.run({'task': 'transfer funds'})

from haystack import Pipeline

@component
class ApprovalGate:
    @component.output_types(approved=bool)
    def run(self, amount: float):
        return approved=amount < 1000

p = Pipeline()
p.add_component('approval', ApprovalGate())

# Conditional connection
p.connect_condition(
    'router.next_step',
    'approval',
    condition=lambda x: x == 'approval',
    outputs={'approved': 'approved'}
)

result = p.run({'amount': 500.0})

