from haystack import component

from vex import Verifier
from vex.schema import SchemaValidator

@component
class VexSchemaGuard:
    def __init__(self):
        self.verifier = Verifier(project_id="your-project")
        self.validator = SchemaValidator({
            'api_params': {'type': 'object', 'properties': {'url': {'type': 'string'}}},
            'retriever_docs': {'type': 'array', 'items': {'type': 'object'}}
        })

    @component.output_types(validated_data=dict, validation_passed=bool)
    def run(self, data: dict, expected_type: str):
        result = self.validator.validate(data, expected_type)

        verdict = self.verifier.verify(
            check='schema_validation',
            inputs={'data': data, 'type': expected_type},
            output=result
        )

        return validated_data=result.validated, validation_passed=verdict.passed

from haystack import component
from vex import Verifier

@component
class VexActionVerifier:
    def __init__(self):
        self.verifier = Verifier(project_id="your-project")

    @component.output_types(action_verified=bool, risk_score=float)
    def run(self, intended_action: str, proposed_api_call: dict, user_permissions: list):
        check_result = self.verifier.verify(
            check='action_correctness',
            inputs={
                'intent': intended_action,
                'api_call': proposed_api_call,
                'permissions': user_permissions
            },
            conditions={
                'method': 'POST' if 'transfer' in intended_action else 'GET',
                'permission_required': ['write:funds']
            }
        )

        return {
            'action_verified': check_result.passed,
            'risk_score': check_result.score
        }

from haystack import component
from vex import Verifier

@component
class VexRollbackGuard:
    def __init__(self):
        self.verifier = Verifier(project_id="your-project")

    @component.output_types(safe_to_proceed=bool, idempotency_key=str)
    def run(self, operation_id: str, params: dict, pre_state: dict):
        idempotency_check = self.verifier.verify(
            check='idempotency',
            inputs={'operation_id': operation_id, 'params': params},
            cache_ttl='1h'
        )

        rollback_plan = self.generate_rollback(pre_state, params)
        rollback_verified = self.verifier.verify(
            check='rollback_plan_valid',
            inputs={'plan': rollback_plan}
        )

        return {
            'safe_to_proceed': idempotency_check.passed and rollback_verified.passed,
            'idempotency_key': idempotency_check.idempotency_key
        }
